class Solution:
    def longestSubsequence(self, arr, difference):
        n = len(arr)
        dp = [1] * n
        best = 1
        for i in range(n):
            for j in range(i):
                if arr[i] - arr[j] == difference:
                    if dp[j] + 1 > dp[i]:
                        dp[i] = dp[j] + 1
            best = max(best, dp[i])
        return best

