var longestSubsequence = function(arr, difference) {
    const dp = new Map();
    let best = 0;
    for (const v of arr) {
        const cur = (dp.get(v - difference) || 0) + 1;
        dp.set(v, cur);
        if (cur > best) best = cur;
    }
    return best;
};
